#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int i = 2;
    int resposta = 1;
    while (i * i <= n) {
        if (n % i == 0) {
            resposta *= i;
            while (n % i == 0) {
                n /= i;
            }
        }
        i++;
    }
    if (n > 1) {
        resposta *= n;
    }
    printf("%d\n", resposta);
    return 0;
}
